import org.springframework.http.*;
import org.springframework.web.bind.annotation.*;
import org.springframework.validation.annotation.Validated;
import jakarta.validation.constraints.*;
import jakarta.validation.Valid;
import java.net.URI;
import java.util.*;

@RestController
@RequestMapping("/api/v1/users")
class UserController {

    record UserRequest(@NotBlank String name, @Email String email, @Min(18) int age) {}
    record UserResponse(Long id, String name, String email) {}
    record ErrorResponse(String code, String message) {}

    private final Map<Long, UserResponse> store = new HashMap<>();
    private long nextId = 1;

    // GET /api/v1/users — list all
    @GetMapping
    public ResponseEntity<List<UserResponse>> list() {
        return ResponseEntity.ok(new ArrayList<>(store.values()));
    }

    // GET /api/v1/users/{id}
    @GetMapping("/{id}")
    public ResponseEntity<?> getById(@PathVariable Long id) {
        UserResponse user = store.get(id);
        if (user == null)
            return ResponseEntity.status(404)
                .body(new ErrorResponse("USER_NOT_FOUND", "User " + id + " not found"));
        return ResponseEntity.ok(user);
    }

    // POST /api/v1/users — create
    @PostMapping
    public ResponseEntity<?> create(@Valid @RequestBody UserRequest req) {
        // Check for duplicate email
        boolean duplicate = store.values().stream()
            .anyMatch(u -> u.email().equals(req.email()));
        if (duplicate)
            return ResponseEntity.status(409)
                .body(new ErrorResponse("EMAIL_CONFLICT", "Email already registered"));

        long id = nextId++;
        UserResponse user = new UserResponse(id, req.name(), req.email());
        store.put(id, user);
        // 201 Created + Location header
        return ResponseEntity
            .created(URI.create("/api/v1/users/" + id))
            .body(user);
    }

    // PATCH /api/v1/users/{id} — partial update
    @PatchMapping("/{id}")
    public ResponseEntity<?> update(@PathVariable Long id,
                                     @RequestBody Map<String, Object> updates) {
        UserResponse existing = store.get(id);
        if (existing == null) return ResponseEntity.notFound().build();

        String name  = updates.containsKey("name")  ? (String) updates.get("name")  : existing.name();
        String email = updates.containsKey("email") ? (String) updates.get("email") : existing.email();
        store.put(id, new UserResponse(id, name, email));
        return ResponseEntity.ok(store.get(id));
    }

    // DELETE /api/v1/users/{id}
    @DeleteMapping("/{id}")
    public ResponseEntity<Void> delete(@PathVariable Long id) {
        if (!store.containsKey(id)) return ResponseEntity.notFound().build();
        store.remove(id);
        return ResponseEntity.noContent().build(); // 204
    }
}

import org.springframework.http.*;
import org.springframework.validation.FieldError;
import org.springframework.web.bind.MethodArgumentNotValidException;
import org.springframework.web.bind.annotation.*;
import java.util.*;
import java.util.stream.Collectors;

// ── Standard API response wrapper ───────────────────────────────
record ApiResponse<T>(boolean success, T data, ErrorDetail error) {
    static <T> ApiResponse<T> ok(T data) { return new ApiResponse<>(true, data, null); }
    static <T> ApiResponse<T> err(String code, String msg) {
        return new ApiResponse<>(false, null, new ErrorDetail(code, msg, null));
    }
}
record ErrorDetail(String code, String message, Map<String, String> fields) {}

// ── Global exception handler ─────────────────────────────────────
@RestControllerAdvice
class GlobalExceptionHandler {

    // Bean Validation failure → 400 with field errors
    @ExceptionHandler(MethodArgumentNotValidException.class)
    public ResponseEntity<ApiResponse<?>> handleValidation(MethodArgumentNotValidException ex) {
        Map<String, String> fieldErrors = ex.getBindingResult().getFieldErrors().stream()
            .collect(Collectors.toMap(FieldError::getField, FieldError::getDefaultMessage,
                (a,b) -> a)); // merge duplicate field keys
        return ResponseEntity.badRequest()
            .body(new ApiResponse<>(false, null,
                new ErrorDetail("VALIDATION_FAILED", "Request validation failed", fieldErrors)));
    }

    // Custom not-found exception → 404
    @ExceptionHandler(NoSuchElementException.class)
    public ResponseEntity<ApiResponse<?>> handleNotFound(NoSuchElementException ex) {
        return ResponseEntity.status(404)
            .body(ApiResponse.err("NOT_FOUND", ex.getMessage()));
    }

    // Unhandled exceptions → 500
    @ExceptionHandler(Exception.class)
    public ResponseEntity<ApiResponse<?>> handleGeneric(Exception ex) {
        return ResponseEntity.internalServerError()
            .body(ApiResponse.err("INTERNAL_ERROR", "Unexpected error occurred"));
    }
}

// ── Sample controller using the wrapper ──────────────────────────
@RestController @RequestMapping("/api/products")
class ProductController {
    @GetMapping("/{id}")
    public ApiResponse<String> get(@PathVariable Long id) {
        if (id <= 0) throw new NoSuchElementException("Product " + id + " not found");
        return ApiResponse.ok("Product#" + id);
    }
}

