import java.util.*;

public class Q2 {
    static class Product {
        Long id; String name, category; Double price;
        Product(Long id, String n, String c, Double p) { this.id=id; name=n; category=c; price=p; }
        public String toString() { return id+"|"+name+"|"+category+"|"+price; }
    }
    static Map<Long, Product> store = new HashMap<>();

    static Product put(Long id, Product p) {
        p.id = id; store.put(id, p); return p; // full replace
    }

    static Product patch(Long id, Map<String,Object> updates) {
        Product p = store.get(id);
        if (updates.containsKey("name"))     p.name     = (String) updates.get("name");
        if (updates.containsKey("category")) p.category = (String) updates.get("category");
        if (updates.containsKey("price"))    p.price    = ((Number) updates.get("price")).doubleValue();
        return p;
    }

    public static void main(String[] args) {
        store.put(1L, new Product(1L, "Laptop", "Electronics", 999.0));
        System.out.println("Original: " + store.get(1L)); // Laptop|Electronics|999.0

        put(1L, new Product(1L, "Laptop Pro", null, null));
        System.out.println("After PUT: " + store.get(1L)); // Laptop Pro|null|null (full replace)

        store.put(1L, new Product(1L, "Laptop", "Electronics", 999.0)); // reset
        patch(1L, Map.of("price", 1199.0));
        System.out.println("After PATCH: " + store.get(1L)); // Laptop|Electronics|1199.0
    }
}

