public class Q3 {
    static int statusFor(String scenario) {
        return switch (scenario) {
            case "missing_field"     -> 400; // Bad Request
            case "not_found"         -> 404; // Not Found
            case "not_authenticated" -> 401; // Unauthorized (no/bad token)
            case "forbidden"         -> 403; // Forbidden (valid token, no permission)
            case "duplicate_email"   -> 409; // Conflict
            case "server_error"      -> 500; // Internal Server Error
            case "rate_limited"      -> 429; // Too Many Requests
            case "created"           -> 201; // Created
            default -> 200;
        };
    }
    public static void main(String[] args) {
        System.out.println(statusFor("missing_field"));     // 400
        System.out.println(statusFor("not_found"));         // 404
        System.out.println(statusFor("not_authenticated")); // 401
        System.out.println(statusFor("forbidden"));         // 403
        System.out.println(statusFor("duplicate_email"));   // 409
        System.out.println(statusFor("server_error"));      // 500
        System.out.println(statusFor("rate_limited"));      // 429
        System.out.println(statusFor("created"));           // 201
    }
}
